import type { PageLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'

const DOCUMENT_BY_PATH = gql`
	query DocumentByPath($path: String!) {
		documentByPath(path: $path) {
			path
			content
		}
	}
`

interface DocumentByPathResult {
	documentByPath: { path: string; content: string } | null
}

export const load: PageLoad = async ({ params, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch)
	try {
		const data = await client.request<DocumentByPathResult>(DOCUMENT_BY_PATH, {
			path: params.path
		})
		if (!data.documentByPath) {
			return { path: params.path, content: null }
		}
		return {
			path: data.documentByPath.path,
			content: data.documentByPath.content
		}
	} catch {
		return { path: params.path, content: null }
	}
}

func printDocGraphJSON(cmd *cobra.Command, graph *docgraph.Graph) error {
	type graphNode struct {
		ID         string   `json:"id"`
		Path       string   `json:"path"`
		Title      string   `json:"title,omitempty"`
		DependsOn  []string `json:"depends_on,omitempty"`
		Dependents []string `json:"dependents,omitempty"`
	}
	nodes := make([]graphNode, 0, len(graph.Documents))
	for _, doc := range graph.Documents {
		nodes = append(nodes, graphNode{
			ID:         doc.ID,
			Path:       doc.Path,
			Title:      doc.Title,
			DependsOn:  doc.DependsOn,
			Dependents: doc.Dependents,
		})
	}
	sort.Slice(nodes, func(i, j int) bool { return nodes[i].ID < nodes[j].ID })
	enc := json.NewEncoder(cmd.OutOrStdout())
	enc.SetIndent("", "  ")
	return enc.Encode(nodes)
}

func printDocGraphText(cmd *cobra.Command, graph *docgraph.Graph) error {
	if len(graph.Documents) == 0 {
		fmt.Fprintln(cmd.OutOrStdout(), "No documents with ddx: frontmatter found.")
		return nil
	}

	ids := graph.All()
	for _, id := range ids {
		doc := graph.Documents[id]
		deps := ""
		if len(doc.DependsOn) > 0 {
			deps = " -> " + strings.Join(doc.DependsOn, ", ")
		}
		fmt.Fprintf(cmd.OutOrStdout(), "%s  %s%s\n", id, doc.Path, deps)
	}
	return nil
}

func (f *CommandFactory) newDocHistoryCommand() *cobra.Command {

package cmd

import (
	"fmt"
	"os"
	"strings"
)

// Exit codes as per CLI contract
const (
	ExitCodeSuccess         = 0
	ExitCodeGeneralError    = 1
	ExitCodeMissingArg      = 2
	ExitCodeNoConfig        = 3
	ExitCodeInvalidConfig   = 4
	ExitCodeNetworkError    = 5
	ExitCodePersonaNotFound = 6
	ExitCodeBindingExists   = 7
	ExitCodeNoBindings      = 8
)

// ExitError represents an error with a specific exit code
type ExitError struct {
	Code    int
	Message string
}

func (e *ExitError) Error() string {
	return e.Message
}

// NewExitError creates a new exit error
func NewExitError(code int, message string) *ExitError {
	return &ExitError{
		Code:    code,
		Message: message,
	}
}

// HandleError processes command errors and exits with appropriate code
func HandleError(err error) {
	if err == nil {
		os.Exit(ExitCodeSuccess)
		return
	}

	// Check if it's an ExitError
	if exitErr, ok := err.(*ExitError); ok {
		if exitErr.Message != "" {
			_, _ = fmt.Fprintln(os.Stderr, exitErr.Message)
		}
		os.Exit(exitErr.Code)
		return
	}

	// Default error handling
	_, _ = fmt.Fprintln(os.Stderr, err.Error())
	os.Exit(ExitCodeGeneralError)
}

// CheckPersonaNotFound wraps persona not found errors
func CheckPersonaNotFound(err error, personaName string) error {
	if err != nil {
		// Check if it's a persona not found error
		if strings.Contains(err.Error(), fmt.Sprintf("persona '%s' not found", personaName)) ||
			strings.Contains(err.Error(), "not found at personas/") {
			return NewExitError(ExitCodePersonaNotFound,
				fmt.Sprintf("Persona '%s' not found", personaName))
		}
	}
	return err
}

// CheckNoConfig wraps no configuration errors
func CheckNoConfig(err error) error {
	if err != nil {
		// Check various no config scenarios
		if strings.Contains(err.Error(), "no .ddx.yml configuration found") ||
			strings.Contains(err.Error(), "No such file or directory") {
			return NewExitError(ExitCodeNoConfig,
				"No .ddx.yml configuration found")
		}
	}
